for (const item of $input.all()) {
  const now = $now.toUTC().toString().slice(0, 10);
  const daysBeforeEol = $('Config').first().json["Days before EOL"] ?? 30;
  const manyToManyProjectsSoftwareColumn = item.json.EOLDates
  // First, identify items that are EOL today
  item.json.EOL_Today = manyToManyProjectsSoftwareColumn.filter(
    (d) =>
      d["Subversion Release"] === now ||
      d["End Of Life"] === now ||
      d["End Of Support"] === now
  );

  // Create a Set of today's EOL items for quick lookup
  const todayEOLSet = new Set(item.json.EOL_Today);

  // Then filter Past_EOL, excluding items already in EOL_Today
  item.json.Past_EOL = manyToManyProjectsSoftwareColumn.filter(
    (d) =>
      !todayEOLSet.has(d) &&
      (new Date(d["Subversion Release"]) < new Date(now) ||
       new Date(d["End Of Life"]) < new Date(now) ||
       new Date(d["End Of Support"]) < new Date(now))
  );

  const pastEOLSet = new Set(item.json.Past_EOL)
  // Filter EOL_in_x_days, excluding items already in EOL_Today or Past_EOL
  item.json.EOL_in_x_days = manyToManyProjectsSoftwareColumn.filter(
    (d) =>
      !todayEOLSet.has(d) &&
      !pastEOLSet.has(d) &&
      ($now.diff(DateTime.fromJSDate(new Date(d["Subversion Release"])), 'days').days <= daysBeforeEol ||
       $now.diff(DateTime.fromJSDate(new Date(d["End Of Life"])), 'days').days <= daysBeforeEol ||
       $now.diff(DateTime.fromJSDate(new Date(d["End Of Support"])), 'days').days <= daysBeforeEol)
  );

  delete item.json._nc_m2m_EOLDates_EOLProjects;
}
return $input.all();
